"#!/usr/bin/env python3\n\"\"\"\n实验环境安装脚本\n\"\"\"\n\nimport os\nimport sys\nimport subprocess\nimport platform\nfrom pathlib import Path\n\n\ndef check_python_version():\n    \"\"\"检查Python版本\"\"\"\n    required_version = (3, 8)\n    current_version = sys.version_info[:2]\n    \n    if current_version < required_version:\n        print(f\"错误: Python版本需要 {required_version[0]}.{required_version[1]}+，当前版本: {sys.version_info[0]}.{sys.version_info[1]}\")\n        sys.exit(1)\n    \n    print(f\"Python版本检查通过: {sys.version_info[0]}.{sys.version_info[1]}.{sys.version_info[2]}\")\n\n\ndef install_requirements():\n    \"\"\"安装依赖包\"\"\"\n    print(\"\\n安装依赖包...\")\n    \n    # 检查pip是否可用\n    try:\n        subprocess.run([sys.executable, \"-m\", \"pip\", \"--version\"], check=True, capture_output=True)\n    except subprocess.CalledProcessError:\n        print(\"错误: pip不可用，请先安装pip\")\n        sys.exit(1)\n    \n    # 安装requirements.txt中的包\n    requirements_file = \"requirements.txt\"\n    if os.path.exists(requirements_file):\n        print(f\"从 {requirements_file} 安装依赖包...\")\n        cmd = [sys.executable, \"-m\", \"pip\", \"install\", \"-r\", requirements_file]\n        \n        try:\n            result = subprocess.run(cmd, check=True, capture_output=True, text=True)\n            print(\"依赖包安装成功!\")\n        except subprocess.CalledProcessError as e:\n            print(f\"安装依赖包时出错: {e.stderr}\")\n            sys.exit(1)\n    else:\n        print(f\"警告: {requirements_file} 不存在，跳过依赖安装\")\n\n\ndef setup_environment():\n    \"\"\"设置实验环境\"\"\"\n    print(\"\\n设置实验环境...\")\n    \n    # 创建必要的目录\n    directories = [\n        \"results\",\n        \"models\",\n        \"logs\",\n        \"data\",\n        \"experiments/configs\",\n        \"experiments/results\",\n        \"experiments/models\"\n    ]\n    \n    for directory in directories:\n        os.makedirs(directory, exist_ok=True)\n        print(f\"创建目录: {directory}\")\n    \n    # 创建默认配置文件（如果不存在）\n    default_config = \"experiments/configs/default.yaml\"\n    if not os.path.exists(default_config):\n        print(f\"创建默认配置文件: {default_config}\")\n        # 这里可以添加创建默认配置文件的代码\n    \n    print(\"环境设置完成!\")\n\n\def install_mpe_environment():\n    \"\"\"安装MPE环境\"\"\"\n    print(\"\\n安装MPE (Multi-Agent Particle Environment)...\")\n    \n    mpe_dir = \"multiagent-particle-envs\"\n    \n    if os.path.exists(mpe_dir):\n        print(f\"MPE环境已存在: {mpe_dir}\")\n        return\n    \n    print(\"克隆MPE仓库...\")\n    try:\n        subprocess.run(\n            [\"git\", \"clone\", \"https://github.com/openai/multiagent-particle-envs.git\", mpe_dir],\n            check=True,\n            capture_output=True,\n            text=True\n        )\n        \n        # 安装MPE\n        print(\"安装MPE...\")\n        os.chdir(mpe_dir)\n        subprocess.run([sys.executable, \"setup.py\", \"develop\"], check=True, capture_output=True, text=True)\n        os.chdir(\"..\")\n        \n        print(\"MPE环境安装成功!\")\n    except subprocess.CalledProcessError as e:\n        print(f\"安装MPE环境时出错: {e.stderr}\")\n        print(\"注意: MPE环境是可选的，实验可以继续运行\")\n\n\ndef install_smac_environment():\n    \"\"\"安装SMAC环境\"\"\"\n    print(\"\\n安装SMAC (StarCraft II Multi-Agent Challenge)...\")\n    \n    print(\"注意: SMAC环境需要StarCraft II游戏\")\n    print(\"请参考: https://github.com/oxwhirl/smac#installing-starcraft-ii\")\n    \n    try:\n        # 尝试安装SMAC\n        subprocess.run(\n            [sys.executable, \"-m\", \"pip\", \"install\", \"git+https://github.com/oxwhirl/smac.git\"],\n            check=True,\n            capture_output=True,\n            text=True\n        )\n        print(\"SMAC环境安装成功!\")\n    except subprocess.CalledProcessError as e:\n        print(f\"安装SMAC环境时出错: {e.stderr}\")\n        print(\"注意: SMAC环境是可选的，实验可以继续运行\")\n\n\def check_gpu():\n    \"\"\"检查GPU可用性\"\"\"\n    print(\"\\n检查GPU支持...\")\n    \n    try:\n        import torch\n        if torch.cuda.is_available():\n            gpu_count = torch.cuda.device_count()\n            gpu_name = torch.cuda.get_device_name(0) if gpu_count > 0 else \"Unknown\"\n            print(f\"GPU可用: {gpu_count} 个设备\")\n            print(f\"GPU型号: {gpu_name}\")\n            print(f\"CUDA版本: {torch.version.cuda}\")\n        else:\n            print(\"GPU不可用，将使用CPU\")\n    except ImportError:\n        print(\"PyTorch未安装，无法检查GPU\")\n\n\ndef main():\n    \"\"\"主安装函数\"\"\"\n    print(\"=\" * 60)\n    print(\"面向受限环境的集成自适应多智能体通信与协作框架\")\n    print(\"实验环境安装脚本\")\n    print(\"=\" * 60)\n    \n    # 检查Python版本\n    check_python_version()\n    \n    # 安装依赖包\n    install_requirements()\n    \n    # 设置环境\n    setup_environment()\n    \n    # 检查GPU\n    check_gpu()\n    \n    # 可选：安装MPE环境\n    install_mpe = input(\"\\n是否安装MPE环境？(y/n, 默认n): \").lower().strip()\n    if install_mpe == 'y':\n        install_mpe_environment()\n    \n    # 可选：安装SMAC环境\n    install_smac = input(\"\\n是否安装SMAC环境？(y/n, 默认n): \").lower().strip()\n    if install_smac == 'y':\n        install_smac_environment()\n    \n    print(\"\\n\" + \"=\" * 60)\n    print(\"安装完成!\")\n    print(\"=\" * 60)\n    print(\"\\n下一步:\")\n    print(\"1. 运行实验: python experiments/main_experiment.py\")\n    print(\"2. 查看帮助: python experiments/main_experiment.py --help\")\n    print(\"3. 运行测试: python -m pytest tests/\")\n    print(\"\\n配置说明:\")\n    print(\"- 编辑 experiments/configs/default.yaml 修改实验配置\")\n    print(\"- 结果保存在 results/ 目录\")\n    print(\"- 模型保存在 models/ 目录\")\n    \n    # 创建示例运行命令\n    print(\"\\n示例运行命令:\")\n    print(\"python experiments/main_experiment.py --env MPE_Navigation --algorithms MAPPO AdaptiveComm --seeds 42 123\")\n\n\nif __name__ == \"__main__\":\n    main()"